const item = $input.first().json;
const lead = item.body || {};
const blocks = item.content || [];
let haikuText = '';
for (var i = 0; i < blocks.length; i++) {
  if (blocks[i].type === 'text') { haikuText = blocks[i].text || ''; break; }
}
let owner_name = '';
let confidence = 'low';
try {
  const match = haikuText.match(/\{[\s\S]*\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    owner_name = String(parsed.owner_name || '').trim();
    confidence = String(parsed.confidence || 'low');
  }
} catch (e) {}
const now = new Date();
const pad = function(n) { return String(n).padStart(2, '0'); };
const scraped_at = now.getFullYear() + '-' + pad(now.getMonth() + 1) + '-' + pad(now.getDate())
  + ' ' + pad(now.getHours()) + ':' + pad(now.getMinutes()) + ':' + pad(now.getSeconds());
return [{ json: {
  name: lead.name || lead.business_name || '',
  owner_name: owner_name,
  email: lead.email || '',
  phone: lead.phone || '',
  address: lead.address || '',
  domain: lead.domain || '',
  website: lead.website || '',
  category: lead.category || '',
  keyword: lead.keyword || '',
  search_location: lead.search_location || '',
  maps_url: lead.maps_url || '',
  scraped_at: scraped_at,
  confidence: confidence
} }];
